## Goal
Implement a service worker that provides COOP/COEP headers (required for SharedArrayBuffer), offline caching, and proper resource management for the web viewer.

## Why This Task is Critical

### SharedArrayBuffer Requirement
sqlite-wasm performs best with SharedArrayBuffer, which requires:
- Cross-Origin-Opener-Policy: same-origin
- Cross-Origin-Embedder-Policy: require-corp

GitHub Pages and Cloudflare Pages cannot set these headers via config. A Service Worker can inject them.

### Offline Support
Users should be able to access their archives without internet after initial load:
- Cache static assets (HTML, JS, CSS, WASM)
- Cache decrypted database in memory (NOT on disk - security)
- Handle offline gracefully

## Technical Implementation

### Service Worker Registration

```javascript
// web/src/sw-register.js
export async function registerServiceWorker() {
    if (!("serviceWorker" in navigator)) {
        console.warn("Service Workers not supported");
        return null;
    }

    try {
        const registration = await navigator.serviceWorker.register("/sw.js", {
            scope: "/"
        });

        console.log("SW registered:", registration.scope);

        // Wait for activation
        await navigator.serviceWorker.ready;
        console.log("SW ready");

        return registration;
    } catch (error) {
        console.error("SW registration failed:", error);
        throw error;
    }
}

// Check if we have SharedArrayBuffer (indicates COOP/COEP working)
export function hasSharedArrayBuffer() {
    try {
        new SharedArrayBuffer(1);
        return true;
    } catch {
        return false;
    }
}
```

### Service Worker Core

```javascript
// web/public/sw.js
const CACHE_NAME = "cass-v1";
const STATIC_ASSETS = [
    "/",
    "/index.html",
    "/app.js",
    "/app.css",
    "/wasm/sql.js",
    "/wasm/sql-wasm.wasm",
    "/crypto-worker.js"
];

// Install: cache static assets
self.addEventListener("install", (event) => {
    console.log("[SW] Installing...");
    event.waitUntil(
        caches.open(CACHE_NAME)
            .then(cache => {
                console.log("[SW] Caching static assets");
                return cache.addAll(STATIC_ASSETS);
            })
            .then(() => self.skipWaiting())
    );
});

// Activate: clean old caches
self.addEventListener("activate", (event) => {
    console.log("[SW] Activating...");
    event.waitUntil(
        caches.keys()
            .then(keys => Promise.all(
                keys.filter(key => key !== CACHE_NAME)
                    .map(key => {
                        console.log("[SW] Deleting old cache:", key);
                        return caches.delete(key);
                    })
            ))
            .then(() => self.clients.claim())
    );
});

// Fetch: inject COOP/COEP headers + cache-first for static assets
self.addEventListener("fetch", (event) => {
    const url = new URL(event.request.url);

    // Only handle same-origin requests
    if (url.origin !== self.location.origin) {
        return;
    }

    event.respondWith(handleFetch(event.request));
});

async function handleFetch(request) {
    // Try cache first for static assets
    const cached = await caches.match(request);
    if (cached) {
        console.log("[SW] Cache hit:", request.url);
        return addSecurityHeaders(cached.clone());
    }

    // Network fetch
    try {
        const response = await fetch(request);

        // Cache successful GET requests
        if (request.method === "GET" && response.ok) {
            const cache = await caches.open(CACHE_NAME);
            cache.put(request, response.clone());
        }

        return addSecurityHeaders(response);
    } catch (error) {
        console.error("[SW] Fetch failed:", request.url, error);

        // Return offline fallback if available
        if (request.destination === "document") {
            const offlinePage = await caches.match("/offline.html");
            if (offlinePage) return offlinePage;
        }

        throw error;
    }
}

// Inject COOP/COEP headers for SharedArrayBuffer support
function addSecurityHeaders(response) {
    const headers = new Headers(response.headers);

    headers.set("Cross-Origin-Opener-Policy", "same-origin");
    headers.set("Cross-Origin-Embedder-Policy", "require-corp");

    // CSP for extra security
    headers.set("Content-Security-Policy", 
        "default-src self; " +
        "script-src self wasm-unsafe-eval; " +
        "style-src self unsafe-inline; " +
        "img-src self data: blob:; " +
        "connect-src self; " +
        "worker-src self blob:; " +
        "frame-ancestors none;"
    );

    return new Response(response.body, {
        status: response.status,
        statusText: response.statusText,
        headers
    });
}
```

### Update Detection

```javascript
// web/src/sw-update.js
export function setupUpdateListener(registration) {
    registration.addEventListener("updatefound", () => {
        const newWorker = registration.installing;

        newWorker.addEventListener("statechange", () => {
            if (newWorker.state === "installed" && navigator.serviceWorker.controller) {
                // New version available
                showUpdateNotification();
            }
        });
    });
}

function showUpdateNotification() {
    const banner = document.createElement("div");
    banner.className = "update-banner";
    banner.innerHTML = 
        "A new version is available. " +
        "<button onclick=\"location.reload()\">Refresh</button>";
    document.body.prepend(banner);
}
```

### Offline Status Indicator

```javascript
// web/src/offline-status.js
export function initOfflineStatus() {
    const indicator = document.getElementById("offline-indicator");

    function updateStatus() {
        if (navigator.onLine) {
            indicator.classList.remove("offline");
            indicator.textContent = "";
        } else {
            indicator.classList.add("offline");
            indicator.textContent = "Offline";
        }
    }

    window.addEventListener("online", updateStatus);
    window.addEventListener("offline", updateStatus);
    updateStatus();
}
```

